use std::io::stdin;

fn main() {
    let mut buf = String::new();
    for _i in 0..3 {
        let _ = stdin().read_line(&mut buf);
        buf = buf.trim_end().to_string();
    }

    let x = buf.as_bytes();
    let mut ans = true;
    for i in 0..x.len()/ 2 {
        ans = ans && x[i] == x[x.len() - i - 1];
    }

    println!("{}", if ans { "YES" } else { "NO" });
}
